import React from "react";

function Skills() {
  return (
    <>
      <main>
        <h1 className="text-center p-5">Skills</h1>
        <div className="container" style={{ display: "flex", justifyContent: "center", height: "20%" }}>
            <div className="col-4 p-5" style={{ display: "flex", justifyContent: "center", height: "20%" }}>
              <img src="/assets/htmllogo.jpg" alt="htmlLogo"></img>
            </div>
            <div className="col-4 p-5">
              <img src="/assets/csslogo.jpg" alt="cssLogo"></img>
            </div>
            <div className="col-4 p-5">
              <img src="/assets/javascriptlogo.jpg" alt="javascriptLogo"></img>
          </div>
        </div>
      </main>
    </>
  );
}

export default Skills;
